import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void exceedsAtIndex2() {
        // prefixes: 1, 3, 6, 10 → first > 5 is at i=2 (sum=6)
        assertEquals(2, new Solution().firstThresholdIndex(new int[]{1, 2, 3, 4}, 5));
    }

    @Test
    void neverExceeds() {
        assertEquals(-1, new Solution().firstThresholdIndex(new int[]{1, 1, 1}, 10));
    }

    @Test
    void exceedsAtFirst() {
        assertEquals(0, new Solution().firstThresholdIndex(new int[]{10}, 5));
    }

    @Test
    void negativePrefixes() {
        // prefixes: -1, -3, 0, 4 → first > 0 is at i=3 (sum=4)
        assertEquals(3, new Solution().firstThresholdIndex(new int[]{-1, -2, 3, 4}, 0));
    }

    @Test
    void empty() {
        assertEquals(-1, new Solution().firstThresholdIndex(new int[]{}, 0));
    }
}

