class Solution {
    public int firstThresholdIndex(int[] nums, int threshold) {
        int sum = 0;
        for (int i = 0; i < nums.length; i++) {
            sum += nums[i];
            if (sum > threshold) {
                return i;
            }
        }
        return -1;
    }
}
